    /// Lp-normalize a tensor along a dimension.
    ///
    /// Equivalent to `torch.nn.functional.normalize(input, p=2.0, dim=1)`.
    /// Normalizes each slice along `dim` to have unit Lp norm.
    pub fn functional_normalize(
        &mut self,
        input: TensorNodeId,
        p: f64,
        dim: usize,
    ) -> Result<TensorNodeId, AutogradError> {
        let vals = self.tensor_values(input)?;
        let shape = self.tensor_shape(input)?;
        let ndim = shape.len();
        if dim >= ndim {
            return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                ft_dispatch::DispatchKeyError::IncompatibleSet {
                    reason: "normalize: dim out of range",
                },
            )));
        }

        let dim_size = shape[dim];
        let outer: usize = shape[..dim].iter().product();
        let inner: usize = shape[dim + 1..].iter().product();
        let mut result = vals.clone();

        for o in 0..outer {
            for i in 0..inner {
                // Compute Lp norm along dim
                let mut norm = 0.0f64;
                for d in 0..dim_size {
                    let idx = o * dim_size * inner + d * inner + i;
                    norm += vals[idx].abs().powf(p);
                }
                norm = norm.powf(1.0 / p).max(1e-12); // clamp for stability

                for d in 0..dim_size {
                    let idx = o * dim_size * inner + d * inner + i;
                    result[idx] = vals[idx] / norm;
                }
            }
        }

        self.tensor_variable(result, shape, false)
    }

    /// Apply dropout (random zeroing) to a tensor.
    ///
    /// Equivalent to `torch.nn.functional.dropout(input, p=0.5, training=True)`.
    /// During training, randomly zeroes elements with probability `p` and scales
    /// remaining elements by `1/(1-p)`. During eval (training=false), returns input unchanged.
    pub fn functional_dropout(
        &mut self,
        input: TensorNodeId,
        p: f64,
        training: bool,
    ) -> Result<TensorNodeId, AutogradError> {
        if !(0.0..=1.0).contains(&p) {
            return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                ft_dispatch::DispatchKeyError::IncompatibleSet {
                    reason: "dropout: probability p must be in [0, 1]",
                },
            )));
        }

        if !training || p == 0.0 {
            return Ok(input);
        }
        if p >= 1.0 {
            let shape = self.tensor_shape(input)?;
            let numel: usize = shape.iter().product();
            return self.tensor_variable(vec![0.0; numel], shape, false);
        }

        let vals = self.tensor_values(input)?;
        let shape = self.tensor_shape(input)?;
        let scale = 1.0 / (1.0 - p);
        let result: Vec<f64> = vals
            .iter()
            .map(|&v| {
                if self.rng.next_f64() < p {
                    0.0
                } else {
                    v * scale
                }
            })
            .collect();
        self.tensor_variable(result, shape, false)
    }

    /// Look up embeddings from a weight matrix.
    ///
    /// Equivalent to `torch.nn.functional.embedding(input, weight)`.
    /// `input` is a tensor of integer indices, `weight` is `[num_embeddings, embedding_dim]`.
    /// Returns a tensor where each index is replaced by the corresponding row of `weight`.
    pub fn functional_embedding(
        &mut self,
        input: TensorNodeId,
        weight: TensorNodeId,
    ) -> Result<TensorNodeId, AutogradError> {
        let indices = self.tensor_values(input)?;
        let input_shape = self.tensor_shape(input)?;
        let w_vals = self.tensor_values(weight)?;
        let w_shape = self.tensor_shape(weight)?;

        if w_shape.len() != 2 {
            return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                ft_dispatch::DispatchKeyError::IncompatibleSet {
                    reason: "embedding: weight must be 2-D [num_embeddings, embedding_dim]",
                },
            )));
        }
        let num_emb = w_shape[0];
        let emb_dim = w_shape[1];

        let mut result = Vec::with_capacity(indices.len() * emb_dim);
        for &idx_f in &indices {
            if idx_f < 0.0 {
                return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                    ft_dispatch::DispatchKeyError::IncompatibleSet {
                        reason: "embedding: indices must be non-negative",
                    },
                )));
            }
            if idx_f.fract() != 0.0 {
                return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                    ft_dispatch::DispatchKeyError::IncompatibleSet {
                        reason: "embedding: indices must be integer-valued",
                    },
                )));
            }
            let idx = idx_f as usize;
            if idx >= num_emb {
                return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                    ft_dispatch::DispatchKeyError::IncompatibleSet {
                        reason: "embedding: index out of range",
                    },
                )));
            }
            let start = idx * emb_dim;
            result.extend_from_slice(&w_vals[start..start + emb_dim]);
        }

        let mut out_shape = input_shape;
        out_shape.push(emb_dim);
        self.tensor_variable(result, out_shape, false)
    }

    /// Apply a linear transformation: `y = x @ weight^T + bias`.
    ///
    /// Equivalent to `torch.nn.functional.linear(input, weight, bias)`.
    /// `input`: `[*, in_features]`, `weight`: `[out_features, in_features]`,
    /// `bias` (optional): `[out_features]`.
    pub fn functional_linear(
        &mut self,
        input: TensorNodeId,
        weight: TensorNodeId,
        bias: Option<TensorNodeId>,
    ) -> Result<TensorNodeId, AutogradError> {
        let weight_t = self.tensor_transpose(weight, 0, 1)?;
        let output = self.tensor_matmul(input, weight_t)?;
        match bias {
            Some(b) => {
                let out_shape = self.tensor_shape(output)?;
                let expanded = self.tensor_expand(b, out_shape)?;
                self.tensor_add(output, expanded)
            }
            None => Ok(output),
        }
    }

    /// Apply a 1D convolution: `y = conv1d(input, weight, bias)`.
    ///
    /// Equivalent to `torch.nn.functional.conv1d(input, weight, bias, stride, padding)`.
    /// `input`: `[N, C_in, L]`, `weight`: `[C_out, C_in, K]`, `bias` (optional): `[C_out]`.
    pub fn functional_conv1d(
        &mut self,
        input: TensorNodeId,
        weight: TensorNodeId,
        bias: Option<TensorNodeId>,
        stride: usize,
        padding: usize,
    ) -> Result<TensorNodeId, AutogradError> {
        if stride == 0 {
            return Err(Self::incompatible_tensor_args(
                "conv1d: stride must be greater than zero",
            ));
        }

        let input_shape = self.tensor_shape(input)?;
        let weight_shape = self.tensor_shape(weight)?;
        if input_shape.len() != 3 {
            return Err(Self::incompatible_tensor_args(
                "conv1d: input must be 3-D [N, C_in, L]",
            ));
        }
        if weight_shape.len() != 3 {
            return Err(Self::incompatible_tensor_args(
                "conv1d: weight must be 3-D [C_out, C_in, K]",
            ));
        }

        let batch_size = input_shape[0];
        let in_channels = input_shape[1];
        let input_len = input_shape[2];
        let out_channels = weight_shape[0];
        let weight_in_channels = weight_shape[1];
        let kernel_size = weight_shape[2];

        if kernel_size == 0 {
            return Err(Self::incompatible_tensor_args(
                "conv1d: kernel size must be greater than zero",
            ));
        }
        if in_channels != weight_in_channels {
            return Err(Self::incompatible_tensor_args(
                "conv1d: input channels do not match weight",
            ));
        }

        if let Some(bias) = bias {
            let bias_shape = self.tensor_shape(bias)?;
            if bias_shape != vec![out_channels] {
                return Err(Self::incompatible_tensor_args(
                    "conv1d: bias must have shape [C_out]",
                ));
            }
        }

        let padded = if padding > 0 {
            self.tensor_pad(input, &[padding, padding], 0.0)?
        } else {
            input
        };
        let padded_len = input_len + 2 * padding;
        if padded_len < kernel_size {
            return Err(Self::incompatible_tensor_args(
                "conv1d: input too short for kernel size and padding",
            ));
        }

        let output_len = (padded_len - kernel_size) / stride + 1;
        let patch_width = in_channels * kernel_size;
        let mut patches = Vec::with_capacity(output_len);
        for out_index in 0..output_len {
            let start = out_index * stride;
            let patch = self.tensor_narrow(padded, 2, start, kernel_size)?;
            let flat = self.tensor_reshape(patch, vec![batch_size, 1, patch_width])?;
            patches.push(flat);
        }

        let unfolded = self.tensor_cat(&patches, 1)?;
        let weight_flat = self.tensor_reshape(weight, vec![out_channels, patch_width])?;
        let weight_t = self.tensor_transpose(weight_flat, 0, 1)?;
        let weight_us = self.tensor_unsqueeze(weight_t, 0)?;
        let weight_expanded =
            self.tensor_expand(weight_us, vec![batch_size, patch_width, out_channels])?;
        let output = self.tensor_bmm(unfolded, weight_expanded)?;
        let output = self.tensor_transpose(output, 1, 2)?;

        match bias {
            Some(bias) => {
                let bias = self.tensor_reshape(bias, vec![1, out_channels, 1])?;
                let bias = self.tensor_expand(bias, vec![batch_size, out_channels, output_len])?;
                self.tensor_add(output, bias)
            }
            None => Ok(output),
        }
    }

    /// Apply a 2D convolution: `y = conv2d(input, weight, bias)`.
    ///
    /// Equivalent to `torch.nn.functional.conv2d(input, weight, bias, stride, padding)`.
    /// `input`: `[N, C_in, H, W]`, `weight`: `[C_out, C_in, K_h, K_w]`.
    pub fn functional_conv2d(
        &mut self,
        input: TensorNodeId,
        weight: TensorNodeId,
        bias: Option<TensorNodeId>,
        stride: (usize, usize),
        padding: (usize, usize),
    ) -> Result<TensorNodeId, AutogradError> {
        let (stride_h, stride_w) = stride;
        let (padding_h, padding_w) = padding;
        if stride_h == 0 || stride_w == 0 {
            return Err(Self::incompatible_tensor_args(
                "conv2d: stride dimensions must be greater than zero",
            ));
        }

        let input_shape = self.tensor_shape(input)?;
        let weight_shape = self.tensor_shape(weight)?;
        if input_shape.len() != 4 {
            return Err(Self::incompatible_tensor_args(
                "conv2d: input must be 4-D [N, C_in, H, W]",
            ));
        }
        if weight_shape.len() != 4 {
            return Err(Self::incompatible_tensor_args(
                "conv2d: weight must be 4-D [C_out, C_in, K_h, K_w]",
            ));
        }

        let batch_size = input_shape[0];
        let in_channels = input_shape[1];
        let input_h = input_shape[2];
        let input_w = input_shape[3];
        let out_channels = weight_shape[0];
        let weight_in_channels = weight_shape[1];
        let kernel_h = weight_shape[2];
        let kernel_w = weight_shape[3];

        if kernel_h == 0 || kernel_w == 0 {
            return Err(Self::incompatible_tensor_args(
                "conv2d: kernel dimensions must be greater than zero",
            ));
        }
        if in_channels != weight_in_channels {
            return Err(Self::incompatible_tensor_args(
                "conv2d: input channels do not match weight",
            ));
        }

        if let Some(bias) = bias {
            let bias_shape = self.tensor_shape(bias)?;
            if bias_shape != vec![out_channels] {
                return Err(Self::incompatible_tensor_args(
                    "conv2d: bias must have shape [C_out]",
                ));
            }
        }

        let padded = if padding_h > 0 || padding_w > 0 {
            self.tensor_pad(input, &[padding_w, padding_w, padding_h, padding_h], 0.0)?
        } else {
            input
        };
        let padded_h = input_h + 2 * padding_h;
        let padded_w = input_w + 2 * padding_w;
        if padded_h < kernel_h || padded_w < kernel_w {
            return Err(Self::incompatible_tensor_args(
                "conv2d: input too small for kernel size and padding",
            ));
        }

        let output_h = (padded_h - kernel_h) / stride_h + 1;
        let output_w = (padded_w - kernel_w) / stride_w + 1;
        let patch_width = in_channels * kernel_h * kernel_w;
        let mut patches = Vec::with_capacity(output_h * output_w);
        for out_h in 0..output_h {
            let row_start = out_h * stride_h;
            let row_slice = self.tensor_narrow(padded, 2, row_start, kernel_h)?;
            for out_w in 0..output_w {
                let col_start = out_w * stride_w;
                let patch = self.tensor_narrow(row_slice, 3, col_start, kernel_w)?;
                let flat = self.tensor_reshape(patch, vec![batch_size, 1, patch_width])?;
                patches.push(flat);
            }
        }

        let unfolded = self.tensor_cat(&patches, 1)?;
        let weight_flat = self.tensor_reshape(weight, vec![out_channels, patch_width])?;
        let weight_t = self.tensor_transpose(weight_flat, 0, 1)?;
        let weight_us = self.tensor_unsqueeze(weight_t, 0)?;
        let weight_expanded =
            self.tensor_expand(weight_us, vec![batch_size, patch_width, out_channels])?;
        let output = self.tensor_bmm(unfolded, weight_expanded)?;
        let output = self.tensor_transpose(output, 1, 2)?;
        let output =
            self.tensor_reshape(output, vec![batch_size, out_channels, output_h, output_w])?;

        match bias {
            Some(bias) => {
                let bias = self.tensor_reshape(bias, vec![1, out_channels, 1, 1])?;
                let bias =
                    self.tensor_expand(bias, vec![batch_size, out_channels, output_h, output_w])?;
                self.tensor_add(output, bias)
            }
            None => Ok(output),
        }
    }

    /// Apply 3D convolution.
    ///
    /// Equivalent to `torch.nn.functional.conv3d(input, weight, bias, stride, padding)`.
    /// Input: `[N, C_in, D, H, W]`, Weight: `[C_out, C_in, K_d, K_h, K_w]`.
    pub fn functional_conv3d(
        &mut self,
        input: TensorNodeId,
        weight: TensorNodeId,
        bias: Option<TensorNodeId>,
        stride: (usize, usize, usize),
        padding: (usize, usize, usize),
    ) -> Result<TensorNodeId, AutogradError> {
        let (stride_d, stride_h, stride_w) = stride;
        let (padding_d, padding_h, padding_w) = padding;
        if stride_d == 0 || stride_h == 0 || stride_w == 0 {
            return Err(Self::incompatible_tensor_args(
                "conv3d: stride dimensions must be greater than zero",
            ));
        }

        let input_shape = self.tensor_shape(input)?;
        let weight_shape = self.tensor_shape(weight)?;
        if input_shape.len() != 5 {
            return Err(Self::incompatible_tensor_args(
                "conv3d: input must be 5-D [N, C_in, D, H, W]",
            ));
        }
        if weight_shape.len() != 5 {
            return Err(Self::incompatible_tensor_args(
                "conv3d: weight must be 5-D [C_out, C_in, K_d, K_h, K_w]",
            ));
        }

        let batch_size = input_shape[0];
        let in_channels = input_shape[1];
        let input_d = input_shape[2];
        let input_h = input_shape[3];
        let input_w = input_shape[4];
        let out_channels = weight_shape[0];
        let kernel_d = weight_shape[2];
        let kernel_h = weight_shape[3];
        let kernel_w = weight_shape[4];

        if in_channels != weight_shape[1] {
            return Err(Self::incompatible_tensor_args(
                "conv3d: input channels do not match weight",
            ));
        }

        let input_vals = self.tensor_values(input)?;
        let weight_vals = self.tensor_values(weight)?;

        let padded_d = input_d + 2 * padding_d;
        let padded_h = input_h + 2 * padding_h;
        let padded_w = input_w + 2 * padding_w;
        let output_d = (padded_d - kernel_d) / stride_d + 1;
        let output_h = (padded_h - kernel_h) / stride_h + 1;
        let output_w = (padded_w - kernel_w) / stride_w + 1;

        let mut output = vec![0.0; batch_size * out_channels * output_d * output_h * output_w];

        for n in 0..batch_size {
            for oc in 0..out_channels {
                for od in 0..output_d {
                    for oh in 0..output_h {
                        for ow in 0..output_w {
                            let mut sum = 0.0;
                            for ic in 0..in_channels {
                                for kd in 0..kernel_d {
                                    for kh in 0..kernel_h {
                                        for kw in 0..kernel_w {
                                            let id = od * stride_d + kd;
                                            let ih = oh * stride_h + kh;
                                            let iw = ow * stride_w + kw;
                                            let id_orig = id as isize - padding_d as isize;
                                            let ih_orig = ih as isize - padding_h as isize;
                                            let iw_orig = iw as isize - padding_w as isize;
                                            if (0..input_d as isize).contains(&id_orig)
                                                && (0..input_h as isize).contains(&ih_orig)
                                                && (0..input_w as isize).contains(&iw_orig)
                                            {
                                                let in_idx = ((n * in_channels + ic) * input_d
                                                    + id_orig as usize)
                                                    * input_h
                                                    * input_w
                                                    + ih_orig as usize * input_w
                                                    + iw_orig as usize;
                                                let w_idx = ((oc * in_channels + ic) * kernel_d
                                                    + kd)
                                                    * kernel_h
                                                    * kernel_w
                                                    + kh * kernel_w
                                                    + kw;
                                                sum += input_vals[in_idx] * weight_vals[w_idx];
                                            }
                                        }
                                    }
                                }
                            }
                            let out_idx =
                                ((n * out_channels + oc) * output_d + od) * output_h * output_w
                                    + oh * output_w
                                    + ow;
                            output[out_idx] = sum;
                        }
                    }
                }
            }
        }

        let out_node = self.tensor_variable(
            output,
            vec![batch_size, out_channels, output_d, output_h, output_w],
            false,
        )?;

        match bias {
            Some(bias) => {
                let bias = self.tensor_reshape(bias, vec![1, out_channels, 1, 1, 1])?;
                let bias = self.tensor_expand(
                    bias,
                    vec![batch_size, out_channels, output_d, output_h, output_w],
                )?;
                self.tensor_add(out_node, bias)
            }
            None => Ok(out_node),
        }
    }

    /// Apply 1D transposed convolution.
    ///
    /// Equivalent to `torch.nn.functional.conv_transpose1d(input, weight, bias, stride, padding, output_padding)`.
    /// Input: `[N, C_in, L]`, Weight: `[C_in, C_out, K]`.
    pub fn functional_conv_transpose1d(
        &mut self,
        input: TensorNodeId,
        weight: TensorNodeId,
        bias: Option<TensorNodeId>,
        stride: usize,
        padding: usize,
        output_padding: usize,
    ) -> Result<TensorNodeId, AutogradError> {
        if stride == 0 {
            return Err(Self::incompatible_tensor_args(
                "conv_transpose1d: stride must be > 0",
            ));
        }
        let input_shape = self.tensor_shape(input)?;
        let weight_shape = self.tensor_shape(weight)?;
        if input_shape.len() != 3 || weight_shape.len() != 3 {
            return Err(Self::incompatible_tensor_args(
                "conv_transpose1d: input must be 3-D [N, C_in, L], weight 3-D [C_in, C_out, K]",
            ));
        }

        let batch_size = input_shape[0];
        let in_channels = input_shape[1];
        let input_l = input_shape[2];
        let out_channels = weight_shape[1];
        let kernel_l = weight_shape[2];

        if in_channels != weight_shape[0] {
            return Err(Self::incompatible_tensor_args(
                "conv_transpose1d: input channels do not match weight",
            ));
        }

        let input_vals = self.tensor_values(input)?;
        let weight_vals = self.tensor_values(weight)?;

        let output_l = (input_l - 1) * stride - 2 * padding + kernel_l + output_padding;
        let mut output = vec![0.0; batch_size * out_channels * output_l];

        for n in 0..batch_size {
            for ic in 0..in_channels {
                for il in 0..input_l {
                    let in_val = input_vals[(n * in_channels + ic) * input_l + il];
                    for oc in 0..out_channels {
                        for k in 0..kernel_l {
                            let ol = il * stride + k;
                            if ol >= padding && ol - padding < output_l {
                                let w_idx = (ic * out_channels + oc) * kernel_l + k;
                                let out_idx = (n * out_channels + oc) * output_l + (ol - padding);
                                output[out_idx] += in_val * weight_vals[w_idx];
                            }
                        }
                    }
                }
            }
        }

        let out_node =
            self.tensor_variable(output, vec![batch_size, out_channels, output_l], false)?;

        match bias {
            Some(bias) => {
                let bias = self.tensor_reshape(bias, vec![1, out_channels, 1])?;
                let bias = self.tensor_expand(bias, vec![batch_size, out_channels, output_l])?;
                self.tensor_add(out_node, bias)
            }
            None => Ok(out_node),
        }
    }

    /// Apply 2D transposed convolution.
    ///
    /// Equivalent to `torch.nn.functional.conv_transpose2d(input, weight, bias, stride, padding, output_padding)`.
    /// Input: `[N, C_in, H, W]`, Weight: `[C_in, C_out, K_h, K_w]`.
    pub fn functional_conv_transpose2d(
        &mut self,
        input: TensorNodeId,
        weight: TensorNodeId,
        bias: Option<TensorNodeId>,
        stride: (usize, usize),
        padding: (usize, usize),
        output_padding: (usize, usize),
    ) -> Result<TensorNodeId, AutogradError> {
        let (stride_h, stride_w) = stride;
        let (padding_h, padding_w) = padding;
        let (output_padding_h, output_padding_w) = output_padding;
        if stride_h == 0 || stride_w == 0 {
            return Err(Self::incompatible_tensor_args(
                "conv_transpose2d: stride must be > 0",
            ));
        }

        let input_shape = self.tensor_shape(input)?;
        let weight_shape = self.tensor_shape(weight)?;
        if input_shape.len() != 4 || weight_shape.len() != 4 {
            return Err(Self::incompatible_tensor_args(
                "conv_transpose2d: input 4-D [N,C_in,H,W], weight 4-D [C_in,C_out,K_h,K_w]",
            ));
        }

        let batch_size = input_shape[0];
        let in_channels = input_shape[1];
        let input_h = input_shape[2];
        let input_w = input_shape[3];
        let out_channels = weight_shape[1];
        let kernel_h = weight_shape[2];
        let kernel_w = weight_shape[3];

        if in_channels != weight_shape[0] {
            return Err(Self::incompatible_tensor_args(
                "conv_transpose2d: input channels do not match weight",
            ));
        }

        let input_vals = self.tensor_values(input)?;
        let weight_vals = self.tensor_values(weight)?;

        let output_h = (input_h - 1) * stride_h - 2 * padding_h + kernel_h + output_padding_h;
        let output_w = (input_w - 1) * stride_w - 2 * padding_w + kernel_w + output_padding_w;
        let mut output = vec![0.0; batch_size * out_channels * output_h * output_w];

        for n in 0..batch_size {
            for ic in 0..in_channels {
                for ih in 0..input_h {
                    for iw in 0..input_w {
                        let in_val =
                            input_vals[((n * in_channels + ic) * input_h + ih) * input_w + iw];
                        for oc in 0..out_channels {
                            for kh in 0..kernel_h {
                                for kw in 0..kernel_w {
                                    let oh = ih * stride_h + kh;
                                    let ow = iw * stride_w + kw;
                                    if oh >= padding_h
                                        && ow >= padding_w
                                        && oh - padding_h < output_h
                                        && ow - padding_w < output_w
                                    {
                                        let w_idx = ((ic * out_channels + oc) * kernel_h + kh)
                                            * kernel_w
                                            + kw;
                                        let out_idx = ((n * out_channels + oc) * output_h
                                            + (oh - padding_h))
                                            * output_w
                                            + (ow - padding_w);
                                        output[out_idx] += in_val * weight_vals[w_idx];
                                    }
                                }
                            }
                        }
                    }
                }
            }
        }

        let out_node = self.tensor_variable(
            output,
            vec![batch_size, out_channels, output_h, output_w],
            false,
        )?;

        match bias {
            Some(bias) => {
                let bias = self.tensor_reshape(bias, vec![1, out_channels, 1, 1])?;
                let bias =
                    self.tensor_expand(bias, vec![batch_size, out_channels, output_h, output_w])?;
                self.tensor_add(out_node, bias)
            }
            None => Ok(out_node),
        }
    }

    /// Apply 1D average pooling over `[N, C, L]`.
    pub fn functional_avg_pool1d(
        &mut self,
        input: TensorNodeId,
        kernel_size: usize,
        stride: usize,
    ) -> Result<TensorNodeId, AutogradError> {
        let stride = if stride == 0 { kernel_size } else { stride };
        if kernel_size == 0 || stride == 0 {
            return Err(Self::incompatible_tensor_args(
                "avg_pool1d: kernel_size and stride must be greater than zero",
            ));
        }

        let input_shape = self.tensor_shape(input)?;
        if input_shape.len() != 3 {
            return Err(Self::incompatible_tensor_args(
                "avg_pool1d: input must be 3-D [N, C, L]",
            ));
        }
        let output_len =
            Self::validate_pool1d_output_len(input_shape[2], kernel_size, stride, "avg_pool1d")?;

        let mut slices = Vec::with_capacity(output_len);
        for out_index in 0..output_len {
            let start = out_index * stride;
            let patch = self.tensor_narrow(input, 2, start, kernel_size)?;
            let avg = self.tensor_mean_dim(patch, 2)?;
            let avg = self.tensor_unsqueeze(avg, 2)?;
            slices.push(avg);
        }
        self.tensor_cat(&slices, 2)
    }

    /// Apply 1D max pooling over `[N, C, L]`.
    pub fn functional_max_pool1d(
        &mut self,
        input: TensorNodeId,
        kernel_size: usize,
        stride: usize,
    ) -> Result<TensorNodeId, AutogradError> {
        let stride = if stride == 0 { kernel_size } else { stride };
        if kernel_size == 0 || stride == 0 {
            return Err(Self::incompatible_tensor_args(
                "max_pool1d: kernel_size and stride must be greater than zero",
            ));
        }

        let input_shape = self.tensor_shape(input)?;
        if input_shape.len() != 3 {
            return Err(Self::incompatible_tensor_args(
                "max_pool1d: input must be 3-D [N, C, L]",
            ));
        }
        let output_len =
            Self::validate_pool1d_output_len(input_shape[2], kernel_size, stride, "max_pool1d")?;

        let mut slices = Vec::with_capacity(output_len);
        for out_index in 0..output_len {
            let start = out_index * stride;
            let patch = self.tensor_narrow(input, 2, start, kernel_size)?;
            let (max_vals, _) = self.tensor_max_dim(patch, 2)?;
            let max_vals = self.tensor_unsqueeze(max_vals, 2)?;
            slices.push(max_vals);
        }
        self.tensor_cat(&slices, 2)
    }

    /// Apply 2D max pooling over `[N, C, H, W]`.
    pub fn functional_max_pool2d(
        &mut self,
        input: TensorNodeId,
        kernel_size: (usize, usize),
        stride: (usize, usize),
    ) -> Result<TensorNodeId, AutogradError> {
        let (kernel_h, kernel_w) = kernel_size;
        let stride_h = if stride.0 == 0 { kernel_h } else { stride.0 };
        let stride_w = if stride.1 == 0 { kernel_w } else { stride.1 };
        if kernel_h == 0 || kernel_w == 0 || stride_h == 0 || stride_w == 0 {
            return Err(Self::incompatible_tensor_args(
                "max_pool2d: kernel_size and stride dimensions must be greater than zero",
            ));
        }

        let input_shape = self.tensor_shape(input)?;
        if input_shape.len() != 4 {
            return Err(Self::incompatible_tensor_args(
                "max_pool2d: input must be 4-D [N, C, H, W]",
            ));
        }

        let batch_size = input_shape[0];
        let channels = input_shape[1];
        let input_h = input_shape[2];
        let input_w = input_shape[3];
        if input_h < kernel_h || input_w < kernel_w {
            return Err(Self::incompatible_tensor_args(
                "max_pool2d: input smaller than kernel size",
            ));
        }

        let output_h = (input_h - kernel_h) / stride_h + 1;
        let output_w = (input_w - kernel_w) / stride_w + 1;
        let flat_width = kernel_h * kernel_w;
        let flattened_channels = batch_size * channels;
        let mut patches = Vec::with_capacity(output_h * output_w);
        for out_h in 0..output_h {
            let row_start = out_h * stride_h;
            let row_slice = self.tensor_narrow(input, 2, row_start, kernel_h)?;
            for out_w in 0..output_w {
                let col_start = out_w * stride_w;
                let patch = self.tensor_narrow(row_slice, 3, col_start, kernel_w)?;
                let flat = self.tensor_reshape(patch, vec![flattened_channels, flat_width])?;
                let (max_vals, _) = self.tensor_max_dim(flat, 1)?;
                let max_vals = self.tensor_reshape(max_vals, vec![batch_size, channels, 1])?;
                patches.push(max_vals);
            }
        }

        let pooled = self.tensor_cat(&patches, 2)?;
        self.tensor_reshape(pooled, vec![batch_size, channels, output_h, output_w])
    }

    /// Apply 2D average pooling over `[N, C, H, W]`.
    #[allow(clippy::too_many_arguments)]
    pub fn functional_avg_pool2d(
        &mut self,
        input: TensorNodeId,
        kernel_size: (usize, usize),
        stride: (usize, usize),
        padding: (usize, usize),
        ceil_mode: bool,
        count_include_pad: bool,
    ) -> Result<TensorNodeId, AutogradError> {
        let (kernel_h, kernel_w) = kernel_size;
        let stride_h = if stride.0 == 0 { kernel_h } else { stride.0 };
        let stride_w = if stride.1 == 0 { kernel_w } else { stride.1 };
        let (padding_h, padding_w) = padding;
        if kernel_h == 0 || kernel_w == 0 || stride_h == 0 || stride_w == 0 {
            return Err(Self::incompatible_tensor_args(
                "avg_pool2d: kernel_size and stride dimensions must be greater than zero",
            ));
        }

        let input_shape = self.tensor_shape(input)?;
        if input_shape.len() != 4 {
            return Err(Self::incompatible_tensor_args(
                "avg_pool2d: input must be 4-D [N, C, H, W]",
            ));
        }

        let batch_size = input_shape[0];
        let channels = input_shape[1];
        let input_h = input_shape[2];
        let input_w = input_shape[3];
        let padded = if padding_h > 0 || padding_w > 0 {
            self.tensor_pad(input, &[padding_w, padding_w, padding_h, padding_h], 0.0)?
        } else {
            input
        };
        let padded_h = input_h + 2 * padding_h;
        let padded_w = input_w + 2 * padding_w;
        if padded_h < kernel_h || padded_w < kernel_w {
            return Err(Self::incompatible_tensor_args(
                "avg_pool2d: input smaller than kernel size after padding",
            ));
        }

        let output_h = if ceil_mode {
            (padded_h - kernel_h).div_ceil(stride_h) + 1
        } else {
            (padded_h - kernel_h) / stride_h + 1
        };
        let output_w = if ceil_mode {
            (padded_w - kernel_w).div_ceil(stride_w) + 1
        } else {
            (padded_w - kernel_w) / stride_w + 1
        };

        let flattened_channels = batch_size * channels;
        let full_kernel_area = (kernel_h * kernel_w) as f64;
        let mut patches = Vec::with_capacity(output_h * output_w);
        for out_h in 0..output_h {
            let row_start = out_h * stride_h;
            let row_end = (row_start + kernel_h).min(padded_h);
            let row_len = row_end - row_start;
            let row_slice = self.tensor_narrow(padded, 2, row_start, row_len)?;
            for out_w in 0..output_w {
                let col_start = out_w * stride_w;
                let col_end = (col_start + kernel_w).min(padded_w);
                let col_len = col_end - col_start;
                let patch = self.tensor_narrow(row_slice, 3, col_start, col_len)?;
                let flat =
                    self.tensor_reshape(patch, vec![flattened_channels, row_len * col_len])?;
                let sum = self.tensor_sum_dim(flat, 1)?;
                let divisor = if count_include_pad || (padding_h == 0 && padding_w == 0) {
                    self.full(vec![flattened_channels], full_kernel_area, false)?
                } else {
                    self.full(vec![flattened_channels], (row_len * col_len) as f64, false)?
                };
                let avg = self.tensor_div(sum, divisor)?;
                let avg = self.tensor_reshape(avg, vec![batch_size, channels, 1])?;
                patches.push(avg);
            }
        }

        let pooled = self.tensor_cat(&patches, 2)?;
        self.tensor_reshape(pooled, vec![batch_size, channels, output_h, output_w])
    }

    /// Adaptive average pooling for 1-D input `[N, C, L]`.
    ///
    /// Equivalent to `torch.nn.functional.adaptive_avg_pool1d(input, output_size)`.
    pub fn functional_adaptive_avg_pool1d(
        &mut self,
        input: TensorNodeId,
        output_size: usize,
    ) -> Result<TensorNodeId, AutogradError> {
        let (storage, meta) = {
            let tensor = self.tensor_tape.tensor(input)?;
            (tensor.storage()?.to_vec(), tensor.meta().clone())
        };
        let shape = meta.shape();
        if shape.len() != 3 {
            return Err(Self::incompatible_tensor_args(
                "adaptive_avg_pool1d: input must be 3-D [N, C, L]",
            ));
        }
        let (n, c, l_in) = (shape[0], shape[1], shape[2]);
        let l_out = output_size;
        let mut output = Vec::with_capacity(n * c * l_out);

        for b in 0..n {
            for ch in 0..c {
                let base = (b * c + ch) * l_in;
                for ol in 0..l_out {
                    let start = (ol * l_in) / l_out;
                    let end = ((ol + 1) * l_in) / l_out;
                    let count = end - start;
                    let sum: f64 = (start..end).map(|i| storage[base + i]).sum();
                    output.push(sum / count as f64);
                }
            }
        }

        self.tensor_variable(output, vec![n, c, l_out], false)
    }

    /// Adaptive average pooling for 2-D input `[N, C, H, W]`.
    ///
    /// Equivalent to `torch.nn.functional.adaptive_avg_pool2d(input, output_size)`.
    pub fn functional_adaptive_avg_pool2d(
        &mut self,
        input: TensorNodeId,
        output_size: (usize, usize),
    ) -> Result<TensorNodeId, AutogradError> {
        let (storage, meta) = {
            let tensor = self.tensor_tape.tensor(input)?;
            (tensor.storage()?.to_vec(), tensor.meta().clone())
        };
        let shape = meta.shape();
        if shape.len() != 4 {
            return Err(Self::incompatible_tensor_args(
                "adaptive_avg_pool2d: input must be 4-D [N, C, H, W]",
            ));
        }
        let (n, c, h_in, w_in) = (shape[0], shape[1], shape[2], shape[3]);
        let (h_out, w_out) = output_size;
        let mut output = Vec::with_capacity(n * c * h_out * w_out);

        for b in 0..n {
            for ch in 0..c {
                let base = (b * c + ch) * h_in * w_in;
                for oh in 0..h_out {
                    let h_start = (oh * h_in) / h_out;
                    let h_end = ((oh + 1) * h_in) / h_out;
                    for ow in 0..w_out {
                        let w_start = (ow * w_in) / w_out;
                        let w_end = ((ow + 1) * w_in) / w_out;
                        let count = (h_end - h_start) * (w_end - w_start);
                        let mut sum = 0.0;
                        for h in h_start..h_end {
                            for w in w_start..w_end {
                                sum += storage[base + h * w_in + w];
                            }
                        }
                        output.push(sum / count as f64);
                    }
                }
            }
        }

        self.tensor_variable(output, vec![n, c, h_out, w_out], false)
    }

    /// Adaptive average pooling for 3-D input `[N, C, D, H, W]`.
    ///
    /// Equivalent to `torch.nn.functional.adaptive_avg_pool3d(input, output_size)`.
    pub fn functional_adaptive_avg_pool3d(
        &mut self,
        input: TensorNodeId,
        output_size: (usize, usize, usize),
    ) -> Result<TensorNodeId, AutogradError> {
        let (storage, meta) = {
            let tensor = self.tensor_tape.tensor(input)?;
            (tensor.storage()?.to_vec(), tensor.meta().clone())
        };
        let shape = meta.shape();
        if shape.len() != 5 {
            return Err(Self::incompatible_tensor_args(
                "adaptive_avg_pool3d: input must be 5-D [N, C, D, H, W]",
            ));
        }
        let (n, c, d_in, h_in, w_in) = (shape[0], shape[1], shape[2], shape[3], shape[4]);
        let (d_out, h_out, w_out) = output_size;
        let mut output = Vec::with_capacity(n * c * d_out * h_out * w_out);

        for b in 0..n {
            for ch in 0..c {
                let base = (b * c + ch) * d_in * h_in * w_in;
                for od in 0..d_out {
                    let d_start = (od * d_in) / d_out;
                    let d_end = ((od + 1) * d_in) / d_out;
                    for oh in 0..h_out {
                        let h_start = (oh * h_in) / h_out;
                        let h_end = ((oh + 1) * h_in) / h_out;
                        for ow in 0..w_out {
                            let w_start = (ow * w_in) / w_out;
                            let w_end = ((ow + 1) * w_in) / w_out;
                            let count = (d_end - d_start) * (h_end - h_start) * (w_end - w_start);
                            let mut sum = 0.0;
                            for d in d_start..d_end {
                                for h in h_start..h_end {
                                    for w in w_start..w_end {
                                        sum += storage[base + d * h_in * w_in + h * w_in + w];
                                    }
                                }
                            }
                            output.push(sum / count as f64);
                        }
                    }
                }
            }
        }

        self.tensor_variable(output, vec![n, c, d_out, h_out, w_out], false)
    }

    /// Apply layer normalization over the trailing `normalized_shape` dimensions.
    pub fn functional_layer_norm(
        &mut self,
        input: TensorNodeId,
        normalized_shape: Vec<usize>,
        weight: Option<TensorNodeId>,
        bias: Option<TensorNodeId>,
        eps: f64,
    ) -> Result<TensorNodeId, AutogradError> {
        if normalized_shape.is_empty() {
            return Err(Self::incompatible_tensor_args(
                "layer_norm: normalized_shape must be non-empty",
            ));
        }
        let input_shape = self.tensor_shape(input)?;
        let ndim = input_shape.len();
        let normalized_ndim = normalized_shape.len();
        if ndim < normalized_ndim {
            return Err(Self::incompatible_tensor_args(
                "layer_norm: input has fewer dimensions than normalized_shape",
            ));
        }

        let normalized_numel: usize = normalized_shape.iter().product();
        if normalized_numel == 0 {
            return Err(Self::incompatible_tensor_args(
                "layer_norm: normalized_shape must not contain zero dimensions",
            ));
        }

        let start = ndim - normalized_ndim;
        for (offset, &expected) in normalized_shape.iter().enumerate() {
            if input_shape[start + offset] != expected {
                return Err(Self::incompatible_tensor_args(
                    "layer_norm: input trailing dimensions do not match normalized_shape",
                ));
            }
        }

        self.validate_optional_affine(weight, bias, &normalized_shape, "layer_norm")?;

        let batch_numel: usize = if start == 0 {
            1
        } else {
            input_shape[..start].iter().product()
        };
        let flat = self.tensor_reshape(input, vec![batch_numel, normalized_numel])?;
        let mean = self.tensor_mean_dim(flat, 1)?;
        let mean = self.tensor_unsqueeze(mean, 1)?;
        let mean = self.tensor_expand(mean, vec![batch_numel, normalized_numel])?;
        let diff = self.tensor_sub(flat, mean)?;
        let diff_sq = self.tensor_mul(diff, diff)?;
        let var = self.tensor_mean_dim(diff_sq, 1)?;
        let var = self.tensor_unsqueeze(var, 1)?;
        let var = self.tensor_expand(var, vec![batch_numel, normalized_numel])?;
        let eps_t = self.full(vec![batch_numel, normalized_numel], eps, false)?;
        let std = self.tensor_add(var, eps_t)?;
        let std = self.tensor_sqrt(std)?;
        let normalized = self.tensor_div(diff, std)?;
        let mut output = self.tensor_reshape(normalized, input_shape.clone())?;

        if let Some(weight) = weight {
            let mut affine_shape = vec![1usize; start];
            affine_shape.extend_from_slice(&normalized_shape);
            let weight = self.tensor_reshape(weight, affine_shape)?;
            let weight = self.tensor_expand(weight, input_shape.clone())?;
            output = self.tensor_mul(weight, output)?;
        }
        if let Some(bias) = bias {
            let mut affine_shape = vec![1usize; start];
            affine_shape.extend_from_slice(&normalized_shape);
            let bias = self.tensor_reshape(bias, affine_shape)?;
            let bias = self.tensor_expand(bias, input_shape)?;
            output = self.tensor_add(output, bias)?;
        }

        Ok(output)
    }

    /// Apply group normalization over channel groups.
    pub fn functional_group_norm(
        &mut self,
        input: TensorNodeId,
        num_groups: usize,
        weight: Option<TensorNodeId>,
        bias: Option<TensorNodeId>,
        eps: f64,
    ) -> Result<TensorNodeId, AutogradError> {
        if num_groups == 0 {
            return Err(Self::incompatible_tensor_args(
                "group_norm: num_groups must be greater than zero",
            ));
        }

        let input_shape = self.tensor_shape(input)?;
        if input_shape.len() < 2 {
            return Err(Self::incompatible_tensor_args(
                "group_norm: input must have at least 2 dimensions [N, C, ...]",
            ));
        }

        let batch_size = input_shape[0];
        let channels = input_shape[1];
        if channels == 0 {
            return Err(Self::incompatible_tensor_args(
                "group_norm: channel dimension must be greater than zero",
            ));
        }
        if !channels.is_multiple_of(num_groups) {
            return Err(Self::incompatible_tensor_args(
                "group_norm: channels must be divisible by num_groups",
            ));
        }

        self.validate_optional_affine(weight, bias, &[channels], "group_norm")?;

        let channels_per_group = channels / num_groups;
        let spatial: usize = if input_shape.len() > 2 {
            input_shape[2..].iter().product()
        } else {
            1
        };
        let group_numel = channels_per_group * spatial;
        let reshaped = self.tensor_reshape(input, vec![batch_size, num_groups, group_numel])?;
        let mean = self.tensor_mean_dim(reshaped, 2)?;
        let mean = self.tensor_unsqueeze(mean, 2)?;
        let mean = self.tensor_expand(mean, vec![batch_size, num_groups, group_numel])?;
        let diff = self.tensor_sub(reshaped, mean)?;
        let diff_sq = self.tensor_mul(diff, diff)?;
        let var = self.tensor_mean_dim(diff_sq, 2)?;
        let var = self.tensor_unsqueeze(var, 2)?;
        let var = self.tensor_expand(var, vec![batch_size, num_groups, group_numel])?;
        let eps_t = self.full(vec![batch_size, num_groups, group_numel], eps, false)?;
        let std = self.tensor_add(var, eps_t)?;
        let std = self.tensor_sqrt(std)?;
        let normalized = self.tensor_div(diff, std)?;
        let normalized = self.tensor_reshape(normalized, input_shape.clone())?;

        self.apply_optional_affine(normalized, &input_shape, 1, weight, bias)
    }

    /// Apply instance normalization over `[N, C, L]`.
    pub fn functional_instance_norm1d(
        &mut self,
        input: TensorNodeId,
        weight: Option<TensorNodeId>,
        bias: Option<TensorNodeId>,
        eps: f64,
    ) -> Result<TensorNodeId, AutogradError> {
        let input_shape = self.tensor_shape(input)?;
        if input_shape.len() != 3 {
            return Err(Self::incompatible_tensor_args(
                "instance_norm1d: input must be 3-D [N, C, L]",
            ));
        }
        self.functional_group_norm(input, input_shape[1], weight, bias, eps)
    }

    /// Apply instance normalization over `[N, C, H, W]`.
    pub fn functional_instance_norm2d(
        &mut self,
        input: TensorNodeId,
        weight: Option<TensorNodeId>,
        bias: Option<TensorNodeId>,
        eps: f64,
    ) -> Result<TensorNodeId, AutogradError> {
        let input_shape = self.tensor_shape(input)?;
        if input_shape.len() != 4 {
            return Err(Self::incompatible_tensor_args(
                "instance_norm2d: input must be 4-D [N, C, H, W]",
            ));
        }
        self.functional_group_norm(input, input_shape[1], weight, bias, eps)
    }

    /// Apply batch normalization over `[N, C]`.
    ///
    /// Returns `(output, updated_running_mean, updated_running_var)`. In eval mode the
    /// returned running-stat tensors are `None`.
    #[allow(clippy::too_many_arguments)]
    pub fn functional_batch_norm1d(
        &mut self,
        input: TensorNodeId,
        running_mean: Option<TensorNodeId>,
        running_var: Option<TensorNodeId>,
        weight: Option<TensorNodeId>,
        bias: Option<TensorNodeId>,
        training: bool,
        momentum: f64,
        eps: f64,
    ) -> Result<(TensorNodeId, Option<TensorNodeId>, Option<TensorNodeId>), AutogradError> {
        let input_shape = self.tensor_shape(input)?;
        if input_shape.len() != 2 {
            return Err(Self::incompatible_tensor_args(
                "batch_norm1d: input must be 2-D [N, C]",
            ));
        }

        let batch_size = input_shape[0];
        let channels = input_shape[1];
        self.validate_optional_affine(weight, bias, &[channels], "group_norm")?;
        let (output, updated_mean, updated_var) = if training {
            let batch_mean = self.tensor_mean_dim(input, 0)?;
            let mean_us = self.tensor_unsqueeze(batch_mean, 0)?;
            let mean_exp = self.tensor_expand(mean_us, vec![batch_size, channels])?;
            let diff = self.tensor_sub(input, mean_exp)?;
            let diff_sq = self.tensor_mul(diff, diff)?;
            let batch_var = self.tensor_mean_dim(diff_sq, 0)?;
            let eps_t = self.full(vec![channels], eps, false)?;
            let std_t = self.tensor_add(batch_var, eps_t)?;
            let std_t = self.tensor_sqrt(std_t)?;
            let std_us = self.tensor_unsqueeze(std_t, 0)?;
            let std_exp = self.tensor_expand(std_us, vec![batch_size, channels])?;
            let normalized = self.tensor_div(diff, std_exp)?;

            let updated_mean = if let Some(running_mean) = running_mean {
                let one_minus = self.full(vec![channels], 1.0 - momentum, false)?;
                let momentum_t = self.full(vec![channels], momentum, false)?;
                let prev_term = self.tensor_mul(running_mean, one_minus)?;
                let batch_term = self.tensor_mul(batch_mean, momentum_t)?;
                Some(self.tensor_add(prev_term, batch_term)?)
            } else {
                None
            };

            let updated_var = if let Some(running_var) = running_var {
                let bessel = if batch_size > 1 {
                    batch_size as f64 / (batch_size as f64 - 1.0)
                } else {
                    1.0
                };
                let bessel_t = self.full(vec![channels], bessel, false)?;
                let unbiased_batch_var = self.tensor_mul(batch_var, bessel_t)?;
                let one_minus = self.full(vec![channels], 1.0 - momentum, false)?;
                let momentum_t = self.full(vec![channels], momentum, false)?;
                let prev_term = self.tensor_mul(running_var, one_minus)?;
                let batch_term = self.tensor_mul(unbiased_batch_var, momentum_t)?;
                Some(self.tensor_add(prev_term, batch_term)?)
            } else {
                None
            };

            (normalized, updated_mean, updated_var)
        } else {
            let running_mean = running_mean.ok_or_else(|| {
                Self::incompatible_tensor_args(
                    "batch_norm1d: running_mean is required when training is false",
                )
            })?;
            let running_var = running_var.ok_or_else(|| {
                Self::incompatible_tensor_args(
                    "batch_norm1d: running_var is required when training is false",
                )
            })?;
            let mean_us = self.tensor_unsqueeze(running_mean, 0)?;
            let mean_exp = self.tensor_expand(mean_us, vec![batch_size, channels])?;
            let diff = self.tensor_sub(input, mean_exp)?;
            let eps_t = self.full(vec![channels], eps, false)?;
            let std_t = self.tensor_add(running_var, eps_t)?;
            let std_t = self.tensor_sqrt(std_t)?;
            let std_us = self.tensor_unsqueeze(std_t, 0)?;
            let std_exp = self.tensor_expand(std_us, vec![batch_size, channels])?;
            (self.tensor_div(diff, std_exp)?, None, None)
        };

        let output = self.apply_optional_affine(output, &input_shape, 1, weight, bias)?;
        Ok((output, updated_mean, updated_var))
    }

    /// Apply batch normalization over `[N, C, H, W]`.
    ///
    /// Returns `(output, updated_running_mean, updated_running_var)`. In eval mode the
    /// returned running-stat tensors are `None`.
    #[allow(clippy::too_many_arguments)]
    pub fn functional_batch_norm2d(
        &mut self,
        input: TensorNodeId,
        running_mean: Option<TensorNodeId>,
        running_var: Option<TensorNodeId>,
        weight: Option<TensorNodeId>,
        bias: Option<TensorNodeId>,
        training: bool,
        momentum: f64,
        eps: f64,
    ) -> Result<(TensorNodeId, Option<TensorNodeId>, Option<TensorNodeId>), AutogradError> {
        let input_shape = self.tensor_shape(input)?;
        if input_shape.len() != 4 {
            return Err(Self::incompatible_tensor_args(
                "batch_norm2d: input must be 4-D [N, C, H, W]",
            ));
        }

        let batch_size = input_shape[0];
        let channels = input_shape[1];
        let height = input_shape[2];
        let width = input_shape[3];
        let sample_count = batch_size * height * width;
        self.validate_optional_affine(weight, bias, &[channels], "group_norm")?;

        let permuted = self.tensor_permute(input, vec![0, 2, 3, 1])?;
        let flat = self.tensor_reshape(permuted, vec![sample_count, channels])?;
        let (normalized_flat, updated_mean, updated_var) = if training {
            let batch_mean = self.tensor_mean_dim(flat, 0)?;
            let mean_us = self.tensor_unsqueeze(batch_mean, 0)?;
            let mean_exp = self.tensor_expand(mean_us, vec![sample_count, channels])?;
            let diff = self.tensor_sub(flat, mean_exp)?;
            let diff_sq = self.tensor_mul(diff, diff)?;
            let batch_var = self.tensor_mean_dim(diff_sq, 0)?;
            let eps_t = self.full(vec![channels], eps, false)?;
            let std_t = self.tensor_add(batch_var, eps_t)?;
            let std_t = self.tensor_sqrt(std_t)?;
            let std_us = self.tensor_unsqueeze(std_t, 0)?;
            let std_exp = self.tensor_expand(std_us, vec![sample_count, channels])?;
            let normalized = self.tensor_div(diff, std_exp)?;

            let updated_mean = if let Some(running_mean) = running_mean {
                let one_minus = self.full(vec![channels], 1.0 - momentum, false)?;
                let momentum_t = self.full(vec![channels], momentum, false)?;
                let prev_term = self.tensor_mul(running_mean, one_minus)?;
                let batch_term = self.tensor_mul(batch_mean, momentum_t)?;
                Some(self.tensor_add(prev_term, batch_term)?)
            } else {
                None
            };

            let updated_var = if let Some(running_var) = running_var {
                let bessel = if sample_count > 1 {
                    sample_count as f64 / (sample_count as f64 - 1.0)
                } else {
                    1.0
                };
                let bessel_t = self.full(vec![channels], bessel, false)?;
                let unbiased_batch_var = self.tensor_mul(batch_var, bessel_t)?;
                let one_minus = self.full(vec![channels], 1.0 - momentum, false)?;
                let momentum_t = self.full(vec![channels], momentum, false)?;
                let prev_term = self.tensor_mul(running_var, one_minus)?;
                let batch_term = self.tensor_mul(unbiased_batch_var, momentum_t)?;
                Some(self.tensor_add(prev_term, batch_term)?)
            } else {
                None
            };

            (normalized, updated_mean, updated_var)
        } else {
            let running_mean = running_mean.ok_or_else(|| {
                Self::incompatible_tensor_args(
                    "batch_norm2d: running_mean is required when training is false",
                )
            })?;
            let running_var = running_var.ok_or_else(|| {
                Self::incompatible_tensor_args(
                    "batch_norm2d: running_var is required when training is false",
                )
            })?;
            let mean_us = self.tensor_unsqueeze(running_mean, 0)?;
            let mean_exp = self.tensor_expand(mean_us, vec![sample_count, channels])?;
            let diff = self.tensor_sub(flat, mean_exp)?;
            let eps_t = self.full(vec![channels], eps, false)?;
            let std_t = self.tensor_add(running_var, eps_t)?;
            let std_t = self.tensor_sqrt(std_t)?;
            let std_us = self.tensor_unsqueeze(std_t, 0)?;
            let std_exp = self.tensor_expand(std_us, vec![sample_count, channels])?;
            (self.tensor_div(diff, std_exp)?, None, None)
        };

        let reshaped =
            self.tensor_reshape(normalized_flat, vec![batch_size, height, width, channels])?;
        let output = self.tensor_permute(reshaped, vec![0, 3, 1, 2])?;
        let output = self.apply_optional_affine(output, &input_shape, 1, weight, bias)?;
        Ok((output, updated_mean, updated_var))
    }

