    fn validate_index_tensor_values(
        input_shape: &[usize],
        dim: usize,
        index_values: &[f64],
    ) -> Result<(), AutogradError> {
        let Some(&dim_size) = input_shape.get(dim) else {
            return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                ft_dispatch::DispatchKeyError::IncompatibleSet {
                    reason: "index operation dimension out of bounds",
                },
            )));
        };

        let dim_size_i = isize::try_from(dim_size).map_err(|_| {
            AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                ft_dispatch::DispatchKeyError::IncompatibleSet {
                    reason: "index operation dimension is out of range for platform isize",
                },
            ))
        })?;
        for &idx in index_values {
            let idx_i = Self::exact_integer_index_to_isize(
                idx,
                "index tensors must contain finite integer values",
            )?;
            if idx_i < -dim_size_i || idx_i >= dim_size_i {
                return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                    ft_dispatch::DispatchKeyError::IncompatibleSet {
                        reason: "index tensor value out of bounds for input dimension",
                    },
                )));
            }
        }

        Ok(())
    }

    fn stft_window_values(
        &self,
        window: Option<TensorNodeId>,
        win_length: usize,
    ) -> Result<Vec<f64>, AutogradError> {
        match window {
            Some(window_node) => {
                if self.tensor_tape.tensor_requires_grad(window_node)? {
                    return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                        ft_dispatch::DispatchKeyError::IncompatibleSet {
                            reason: "stft/istft: autograd for window tensors is not supported",
                        },
                    )));
                }
                let window_tensor = self.tensor_tape.tensor(window_node)?;
                if window_tensor.meta().shape() != [win_length] {
                    return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                        ft_dispatch::DispatchKeyError::IncompatibleSet {
                            reason: "stft/istft: window must be 1-D with length win_length",
                        },
                    )));
                }
                match window_tensor.typed_storage() {
                    TensorStorage::F32(values) => {
                        Ok(values.iter().map(|&v| f64::from(v)).collect::<Vec<_>>())
                    }
                    TensorStorage::F64(values) => Ok(values.as_ref().clone()),
                    _ => Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                        ft_dispatch::DispatchKeyError::IncompatibleSet {
                            reason: "stft/istft: window must be float32 or float64",
                        },
                    ))),
                }
            }
            None => Ok(vec![1.0; win_length]),
        }
    }

    fn affine_grid_axis_coordinate(index: usize, size: usize, align_corners: bool) -> f64 {
        if size <= 1 {
            0.0
        } else if align_corners {
            -1.0 + 2.0 * index as f64 / (size - 1) as f64
        } else {
            -1.0 + (2.0 * index as f64 + 1.0) / size as f64
        }
    }

    fn grid_sampler_unnormalize(coord: f64, size: usize, align_corners: bool) -> f64 {
        if align_corners {
            ((coord + 1.0) * (size.saturating_sub(1)) as f64) / 2.0
        } else {
            ((coord + 1.0) * size as f64 - 1.0) / 2.0
        }
    }

    fn grid_sampler_reflect(coord: f64, size: usize, align_corners: bool) -> f64 {
        if size <= 1 {
            return 0.0;
        }
        let (low, high) = if align_corners {
            (0.0, (size - 1) as f64)
        } else {
            (-0.5, size as f64 - 0.5)
        };
        let span = high - low;
        if span == 0.0 {
            return 0.0;
        }
        let period = 2.0 * span;
        let mut shifted = (coord - low).rem_euclid(period);
        if shifted > span {
            shifted = period - shifted;
        }
        (low + shifted).clamp(0.0, (size - 1) as f64)
    }

    fn grid_sample_f64(input: &[f64], grid: &[f64], plan: GridSamplePlan) -> Vec<f64> {
        let mut output = vec![0.0; plan.batch * plan.channels * plan.out_h * plan.out_w];

        let sample_value = |n: usize, c: usize, y: isize, x: isize| -> f64 {
            if y < 0 || y >= plan.in_h as isize || x < 0 || x >= plan.in_w as isize {
                0.0
            } else {
                let idx =
                    ((n * plan.channels + c) * plan.in_h + y as usize) * plan.in_w + x as usize;
                input[idx]
            }
        };

        for n in 0..plan.batch {
            for h in 0..plan.out_h {
                for w in 0..plan.out_w {
                    let grid_base = ((n * plan.out_h + h) * plan.out_w + w) * 2;
                    let mut x = grid[grid_base];
                    let mut y = grid[grid_base + 1];
                    if x.is_nan() {
                        x = -1.0;
                    }
                    if y.is_nan() {
                        y = -1.0;
                    }

                    let mut ix = Self::grid_sampler_unnormalize(x, plan.in_w, plan.align_corners);
                    let mut iy = Self::grid_sampler_unnormalize(y, plan.in_h, plan.align_corners);
                    match plan.padding_mode {
                        GridSamplePaddingMode::Zeros => {}
                        GridSamplePaddingMode::Border => {
                            ix = ix.clamp(0.0, (plan.in_w.saturating_sub(1)) as f64);
                            iy = iy.clamp(0.0, (plan.in_h.saturating_sub(1)) as f64);
                        }
                        GridSamplePaddingMode::Reflection => {
                            ix = Self::grid_sampler_reflect(ix, plan.in_w, plan.align_corners);
                            iy = Self::grid_sampler_reflect(iy, plan.in_h, plan.align_corners);
                        }
                    }

                    for c in 0..plan.channels {
                        let value = match plan.mode {
                            GridSampleMode::Nearest => {
                                let nearest_x = ix.round() as isize;
                                let nearest_y = iy.round() as isize;
                                match plan.padding_mode {
                                    GridSamplePaddingMode::Zeros => {
                                        sample_value(n, c, nearest_y, nearest_x)
                                    }
                                    GridSamplePaddingMode::Border
                                    | GridSamplePaddingMode::Reflection => sample_value(
                                        n,
                                        c,
                                        nearest_y.clamp(0, plan.in_h as isize - 1),
                                        nearest_x.clamp(0, plan.in_w as isize - 1),
                                    ),
                                }
                            }
                            GridSampleMode::Bilinear => {
                                let x0 = ix.floor();
                                let y0 = iy.floor();
                                let x1 = x0 + 1.0;
                                let y1 = y0 + 1.0;
                                let wx1 = ix - x0;
                                let wy1 = iy - y0;
                                let wx0 = 1.0 - wx1;
                                let wy0 = 1.0 - wy1;
                                let v00 = sample_value(n, c, y0 as isize, x0 as isize);
                                let v01 = sample_value(n, c, y0 as isize, x1 as isize);
                                let v10 = sample_value(n, c, y1 as isize, x0 as isize);
                                let v11 = sample_value(n, c, y1 as isize, x1 as isize);
                                v00 * wx0 * wy0
                                    + v01 * wx1 * wy0
                                    + v10 * wx0 * wy1
                                    + v11 * wx1 * wy1
                            }
                        };
                        let out_idx = ((n * plan.channels + c) * plan.out_h + h) * plan.out_w + w;
                        output[out_idx] = value;
                    }
                }
            }
        }

        output
    }

    fn istft_reconstruct_f64(
        &self,
        spectrogram: Vec<ft_core::Complex128>,
        plan: IstftReconstructPlan<'_>,
    ) -> Vec<f64> {
        let output_len = if plan.frames == 0 {
            0
        } else {
            plan.n_fft + plan.hop_length * (plan.frames - 1)
        };
        let mut signal = vec![0.0; output_len];
        let mut envelope = vec![0.0; output_len];
        let scale = if plan.normalized {
            1.0 / (plan.n_fft as f64).sqrt()
        } else {
            1.0 / plan.n_fft as f64
        };

        for frame_idx in 0..plan.frames {
            let mut full_spectrum = vec![ft_core::Complex128::new(0.0, 0.0); plan.n_fft];
            if plan.onesided {
                for k in 0..plan.freq_bins {
                    full_spectrum[k] = spectrogram[k * plan.frames + frame_idx];
                }
                let upper = if plan.n_fft.is_multiple_of(2) {
                    plan.freq_bins.saturating_sub(1)
                } else {
                    plan.freq_bins
                };
                for k in 1..upper {
                    full_spectrum[plan.n_fft - k] = full_spectrum[k].conj();
                }
            } else {
                for k in 0..plan.n_fft {
                    full_spectrum[k] = spectrogram[k * plan.frames + frame_idx];
                }
            }

            let mut frame_time = vec![0.0; plan.n_fft];
            for (n, sample) in frame_time.iter_mut().enumerate() {
                let mut value = ft_core::Complex128::new(0.0, 0.0);
                for (k, coeff) in full_spectrum.iter().enumerate() {
                    let angle =
                        2.0 * std::f64::consts::PI * k as f64 * n as f64 / plan.n_fft as f64;
                    let twiddle = ft_core::Complex128::new(angle.cos(), angle.sin());
                    value += *coeff * twiddle;
                }
                *sample = value.re * scale;
            }

            let start = frame_idx * plan.hop_length;
            for i in 0..plan.window_values.len() {
                let sample = frame_time[plan.window_pad + i] * plan.window_values[i];
                signal[start + i] += sample;
                envelope[start + i] += plan.window_values[i] * plan.window_values[i];
            }
        }

        for (sample, norm) in signal.iter_mut().zip(envelope.iter()) {
            if *norm > 1e-12 {
                *sample /= *norm;
            }
        }

        let mut trimmed = if plan.center {
            let pad = plan.n_fft / 2;
            if signal.len() >= 2 * pad {
                signal[pad..signal.len() - pad].to_vec()
            } else {
                Vec::new()
            }
        } else {
            signal
        };

        if let Some(target_len) = plan.length {
            match trimmed.len().cmp(&target_len) {
                std::cmp::Ordering::Greater => trimmed.truncate(target_len),
                std::cmp::Ordering::Less => trimmed.resize(target_len, 0.0),
                std::cmp::Ordering::Equal => {}
            }
        }
        trimmed
    }

    pub fn tensor_index_select(
        &mut self,
        input: TensorNodeId,
        dim: usize,
        indices: TensorNodeId,
    ) -> Result<TensorNodeId, AutogradError> {
        let input_shape = self.tensor_shape(input)?;
        let indices_data = self.tensor_tape.values(indices)?;
        Self::validate_index_tensor_values(&input_shape, dim, &indices_data)?;
        self.tensor_tape.index_select(input, dim, &indices_data)
    }

    pub fn tensor_gather(
        &mut self,
        input: TensorNodeId,
        dim: usize,
        index: TensorNodeId,
    ) -> Result<TensorNodeId, AutogradError> {
        let input_shape = self.tensor_shape(input)?;
        let index_data = self.tensor_tape.values(index)?;
        Self::validate_index_tensor_values(&input_shape, dim, &index_data)?;
        let index_shape = self.tensor_tape.tensor(index)?.meta().shape().to_vec();
        self.tensor_tape
            .gather(input, dim, &index_data, index_shape)
    }

    pub fn tensor_scatter(
        &mut self,
        input: TensorNodeId,
        dim: usize,
        index: TensorNodeId,
        src: TensorNodeId,
    ) -> Result<TensorNodeId, AutogradError> {
        let input_shape = self.tensor_shape(input)?;
        let index_data = self.tensor_tape.values(index)?;
        Self::validate_index_tensor_values(&input_shape, dim, &index_data)?;
        let index_shape = self.tensor_tape.tensor(index)?.meta().shape().to_vec();
        let src_data = self.tensor_tape.values(src)?;
        self.tensor_tape
            .scatter(input, dim, &index_data, index_shape, &src_data)
    }

    pub fn tensor_scatter_add(
        &mut self,
        input: TensorNodeId,
        dim: usize,
        index: TensorNodeId,
        src: TensorNodeId,
    ) -> Result<TensorNodeId, AutogradError> {
        let input_shape = self.tensor_shape(input)?;
        let index_data = self.tensor_tape.values(index)?;
        Self::validate_index_tensor_values(&input_shape, dim, &index_data)?;
        let index_shape = self.tensor_tape.tensor(index)?.meta().shape().to_vec();
        let src_data = self.tensor_tape.values(src)?;
        self.tensor_tape
            .scatter_add(input, dim, &index_data, index_shape, &src_data)
    }

    pub fn tensor_index_put(
        &mut self,
        input: TensorNodeId,
        indices: &[TensorNodeId],
        values: TensorNodeId,
        accumulate: bool,
    ) -> Result<TensorNodeId, AutogradError> {
        let idx_data: Vec<Vec<f64>> = indices
            .iter()
            .map(|&idx| self.tensor_tape.values(idx))
            .collect::<Result<_, _>>()?;
        let vals_data = self.tensor_tape.values(values)?;
        self.tensor_tape
            .index_put(input, &idx_data, &vals_data, accumulate)
    }

    pub fn tensor_masked_fill(
        &mut self,
        input: TensorNodeId,
        mask: TensorNodeId,
        value: f64,
    ) -> Result<TensorNodeId, AutogradError> {
        let shape = self.tensor_shape(input)?;
        let fill_tensor = self.full(shape, value, false)?;
        self.tensor_where(mask, fill_tensor, input)
    }

    /// Accumulate `src` into `self` at positions specified by `index` along `dim`.
    ///
    /// Equivalent to `tensor.index_add_(dim, index, source)`.
    /// For each `i`, adds `src[i]` to `self[index[i]]` along `dim`.
    pub fn tensor_index_add(
        &mut self,
        input: TensorNodeId,
        dim: usize,
        index: TensorNodeId,
        src: TensorNodeId,
    ) -> Result<TensorNodeId, AutogradError> {
        let mut result = self.tensor_values(input)?;
        let shape = self.tensor_shape(input)?;
        let idx_vals = self.tensor_values(index)?;
        let src_vals = self.tensor_values(src)?;
        let src_shape = self.tensor_shape(src)?;

        let ndim = shape.len();
        if dim >= ndim {
            return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                ft_dispatch::DispatchKeyError::IncompatibleSet {
                    reason: "index_add: dim out of range",
                },
            )));
        }

        let dim_size = shape[dim];
        let outer: usize = shape[..dim].iter().product();
        let inner: usize = shape[dim + 1..].iter().product();
        let src_dim_size = src_shape.get(dim).copied().unwrap_or(1);

        for o in 0..outer {
            for (si, &idx_f) in idx_vals.iter().enumerate() {
                if !idx_f.is_finite() || idx_f < 0.0 || idx_f != idx_f.floor() {
                    return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                        ft_dispatch::DispatchKeyError::IncompatibleSet {
                            reason: "index_add: index values must be finite non-negative integers",
                        },
                    )));
                }
                let idx = idx_f as usize;
                if idx >= dim_size {
                    return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                        ft_dispatch::DispatchKeyError::IncompatibleSet {
                            reason: "index_add: index value out of range",
                        },
                    )));
                }
                if si >= src_dim_size {
                    continue;
                }
                for i in 0..inner {
                    let dst_offset = o * dim_size * inner + idx * inner + i;
                    let src_offset = o * src_dim_size * inner + si * inner + i;
                    if dst_offset < result.len() && src_offset < src_vals.len() {
                        result[dst_offset] += src_vals[src_offset];
                    }
                }
            }
        }

        self.tensor_variable(result, shape, false)
    }

    /// Copy `src` into `self` at positions specified by `index` along `dim`.
    ///
    /// Equivalent to `tensor.index_copy_(dim, index, source)`.
    pub fn tensor_index_copy(
        &mut self,
        input: TensorNodeId,
        dim: usize,
        index: TensorNodeId,
        src: TensorNodeId,
    ) -> Result<TensorNodeId, AutogradError> {
        let mut result = self.tensor_values(input)?;
        let shape = self.tensor_shape(input)?;
        let idx_vals = self.tensor_values(index)?;
        let src_vals = self.tensor_values(src)?;
        let src_shape = self.tensor_shape(src)?;

        let ndim = shape.len();
        if dim >= ndim {
            return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                ft_dispatch::DispatchKeyError::IncompatibleSet {
                    reason: "index_copy: dim out of range",
                },
            )));
        }

        let dim_size = shape[dim];
        let outer: usize = shape[..dim].iter().product();
        let inner: usize = shape[dim + 1..].iter().product();
        let src_dim_size = src_shape.get(dim).copied().unwrap_or(1);

        for o in 0..outer {
            for (si, &idx_f) in idx_vals.iter().enumerate() {
                if !idx_f.is_finite() || idx_f < 0.0 || idx_f != idx_f.floor() {
                    return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                        ft_dispatch::DispatchKeyError::IncompatibleSet {
                            reason: "index_copy: index values must be finite non-negative integers",
                        },
                    )));
                }
                let idx = idx_f as usize;
                if idx >= dim_size {
                    return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                        ft_dispatch::DispatchKeyError::IncompatibleSet {
                            reason: "index_copy: index value out of range",
                        },
                    )));
                }
                if si >= src_dim_size {
                    continue;
                }
                for i in 0..inner {
                    let dst_offset = o * dim_size * inner + idx * inner + i;
                    let src_offset = o * src_dim_size * inner + si * inner + i;
                    if dst_offset < result.len() && src_offset < src_vals.len() {
                        result[dst_offset] = src_vals[src_offset];
                    }
                }
            }
        }

        self.tensor_variable(result, shape, false)
    }

    /// Fill positions specified by `index` along `dim` with a scalar value.
    ///
    /// Equivalent to `tensor.index_fill_(dim, index, value)`.
    pub fn tensor_index_fill(
        &mut self,
        input: TensorNodeId,
        dim: usize,
        index: TensorNodeId,
        value: f64,
    ) -> Result<TensorNodeId, AutogradError> {
        let mut result = self.tensor_values(input)?;
        let shape = self.tensor_shape(input)?;
        let idx_vals = self.tensor_values(index)?;

        let ndim = shape.len();
        if dim >= ndim {
            return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                ft_dispatch::DispatchKeyError::IncompatibleSet {
                    reason: "index_fill: dim out of range",
                },
            )));
        }

        let dim_size = shape[dim];
        let outer: usize = shape[..dim].iter().product();
        let inner: usize = shape[dim + 1..].iter().product();

        for o in 0..outer {
            for &idx_f in &idx_vals {
                if !idx_f.is_finite() || idx_f < 0.0 || idx_f != idx_f.floor() {
                    return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                        ft_dispatch::DispatchKeyError::IncompatibleSet {
                            reason: "index_fill: index values must be finite non-negative integers",
                        },
                    )));
                }
                let idx = idx_f as usize;
                if idx >= dim_size {
                    return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                        ft_dispatch::DispatchKeyError::IncompatibleSet {
                            reason: "index_fill: index value out of range",
                        },
                    )));
                }
                for i in 0..inner {
                    let offset = o * dim_size * inner + idx * inner + i;
                    if offset < result.len() {
                        result[offset] = value;
                    }
                }
            }
        }

        self.tensor_variable(result, shape, false)
    }

    pub fn tensor_cat(
        &mut self,
        inputs: &[TensorNodeId],
        dim: usize,
    ) -> Result<TensorNodeId, AutogradError> {
        let (out, event) = self.tensor_tape.cat(inputs, dim, self.mode())?;
        self.record_tensor_join_operation(&event);
        Ok(out)
    }

    pub fn tensor_stack(
        &mut self,
        inputs: &[TensorNodeId],
        dim: usize,
    ) -> Result<TensorNodeId, AutogradError> {
        let (out, event) = self.tensor_tape.stack(inputs, dim, self.mode())?;
        self.record_tensor_join_operation(&event);
        Ok(out)
    }

